var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 전, 로터스 아마니 밸리.","JPN":"数日前、ロータスアマニーバレー。","ENG":"A few days ago, Lotus, Amani Valley.","TWN":"幾天前，洛德斯阿瑪尼山谷。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_STARVE"},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으으… 좋은 냄새…","JPN":"うう……いい匂い……","ENG":"Mm... It smells so good...","TWN":"呃呃…味道好香…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"한 팩만 달라고 하면 분명 신고 당하겠지?","JPN":"1パックだけほしいって言ったら、通報されるかな？","ENG":"I'll get reported if I ask for a pack, right?","TWN":"只要一包的話肯定會被檢舉吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…팔 하나 잘라볼까? 응급 환자인 척 쓰러지면 수혈이라도 해주지 않으려나?","JPN":"……腕を切ってみようかな？　緊急患者のふりをして倒れたら、輸血してもらえたりして……","ENG":"...Maybe I should cut off an arm? Won't they give me a blood transfusion if I pretend to be an emergency patient?","TWN":"…要不要砍斷一隻手臂？裝作是急救患者昏倒的話，他們會幫忙輸血嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"감시원들 눈을 피해 무슨 음모를 꾸미나 했더니…","JPN":"監視の目を逃れて何を企んでいるのかと思えば……","ENG":"I was wondering what you were up to avoiding the guards' eyes, but...","TWN":"我還在想妳會避開監視人員的視線，策畫什麼陰謀…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"대로변에 숨어 자해공갈을 계획하고 있을 줄은 몰랐군요.","JPN":"道端に隠れて自害作戦を立てていたとは心外ですね。","ENG":"I didn't expect you to be hiding on the side of the road, plotting to hurt yourself.","TWN":"沒想到妳居然躲在大馬路邊計畫自殘恐嚇。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗… 관리국 깡패…!","JPN":"あっ、管理局のごろつき……！","ENG":"Huh...?! The Administration gangster...!","TWN":"啊…管理局流氓…！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 깡패가 아닙니다.","JPN":"私はごろつきではありません。","ENG":"I am not a gangster.","TWN":"我不是流氓。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"거짓말! 처음 만났을 때부터 날 피냐타처럼 때려 놓고선!","JPN":"嘘！　初めて会った時だって私をピニャータみたに叩き潰したくせに！","ENG":"Liar! You beat me up like a piñata when we first met!","TWN":"騙人！你從第一次見面就把我當皮納塔一樣打了一頓！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어 소집 회담 때를 말하는 겁니까?","JPN":"シニア召集会談の時の話ですか？","ENG":"Are you talking about the Senior convention meeting?","TWN":"妳指的是Senior召集會談的時候嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"전 당신이 여직원의 목덜미를 노리고 이빨을 드러내기에 제지했을 뿐입니다.","JPN":"私はあなたが牙を剥いて、女性社員の首元を狙おうとしたから阻止しただけです。","ENG":"I only stopped you because you showed your teeth and tried to bite the back of a female employee's neck.","TWN":"我只不過是阻止妳覬覦女員工的脖子露出牙齒而已。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그때는 이상한 변태라고만 생각했는데… 과거의 사정을 알고 나니 명백한 흡혈 시도였군요.","JPN":"あの時はただの変態だと思いましたが……あれは意図した吸血のための行動だったのですね。","ENG":"At the time, I thought you were just a pervert, but... now that I think back on it, you were trying to suck on her blood.","TWN":"我當時只以為妳是個奇怪的變態…但知道過去的事情之後，原來那是明擺著試圖吸血啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그, 그땐 마스크를 잃어버려서 그랬어요!","JPN":"あ、あの時はマスクをなくしたから仕方なかったんです！","ENG":"I-it's because I lost my mask back then!","TWN":"那、那時候是因為我把口罩弄丟了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"냄새 때문에 아찔해지긴 했지만, 그래도 물지는 않았다고요!","JPN":"匂いのせいで一瞬意識が飛んだけど、噛まずに済んだじゃないですか！","ENG":"The smell made me a little dizzy, but I didn't bite!","TWN":"雖然的確因為味道變得暈頭轉向，但我還是沒咬人！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"동물 피 같은 걸론 해소할 수 없는 겁니까?","JPN":"あの衝動は動物の血では解消できないのですか？","ENG":"Can't you satiate yourself with animal blood?","TWN":"不能用動物血之類的東西消除嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하, 그야 안되죠. 절 짐승쯤으로 여기는 건가요?","JPN":"当たり前でしょう。私を獣扱いしないでくれますか？","ENG":"*Sigh* Nope. Do you think I'm an animal or something?","TWN":"哈，當然不行，難道你把我當成禽獸嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"인간 피를 노리는 쪽도 짐승인 건 매한가지라 생각합니다만.","JPN":"人間の血を狙っている時点で獣と変わらないと思いますが。","ENG":"You're not less of an animal to be seeking human blood, though.","TWN":"雖然我認為覬覦人血也和禽獸沒有兩樣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"따라오시죠. 시니어님 방에 응급용 혈액팩을 비축해둔 게 좀 있습니다.","JPN":"ついてきてください。シニアの部屋に、保存しておいた緊急用の血液パックが少しあります。","ENG":"Follow me. There should be some emergency blood packs stored in the Senior's office.","TWN":"跟我來吧，Senior房間裡有一些應急用的血袋。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진짜요? 앗싸!","JPN":"本当ですか？　やったー！","ENG":"Really? Awesome!","TWN":"真的嗎？好耶！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데, 저 벌 주려고 온 거 아니었어요? 당연히 감옥에 갇힐 줄 알았는데.","JPN":"でも、私を懲らしめるために来たのでは？　牢に放り込まれると思ってたのに。","ENG":"But didn't you come to find and punish me? I thought you were throwing me in jail.","TWN":"不過，你不是來懲罰我的嗎？我還以為自己當然會被關進監獄。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당장 그럴 일은 없을 겁니다.","JPN":"すぐにはしません。","ENG":"That won't be happening, at least, not right now.","TWN":"暫時不會發生那種事。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진심? 저 그럼 자유에요?","JPN":"本当？　じゃあ私って自由ですか？","ENG":"Seriously? Then, I'm free?","TWN":"真的？那我是自由的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"진실을 캐묻기 위한 잔혹한 고문… 같은 것도 안 당하나요?","JPN":"真実を吐き出させるための残酷な拷問……とかもないですか？","ENG":"You're not even going to... torture me for the truth?","TWN":"也不會遭受為了追查真相的殘酷拷問…之類的事嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"왜 그 부분에서 아쉬워하는진 모르겠습니다만…","JPN":"なぜ残念そうな顔をするのか理解できませんが……","ENG":"I don't know what you are expecting, but...","TWN":"雖然不知道妳為什麼要對這部分感到可惜…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"당신의 처분은 잠시 유예됐을 뿐입니다. 당신의 죄를 입증할 주요인물이 실종된 상태니까요.","JPN":"あなたの処分については、決定が少し猶予されただけです。あなたの罪を証明できる主要人物が行方不明なので。","ENG":"Your disposition has only been temporarily postponed. Because the key person who can prove your crime is missing at the moment.","TWN":"但妳的處分只是暫緩而已，因為能證實妳罪行的主要人物失蹤了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아…","JPN":"あ……","ENG":"Ah...","TWN":"啊…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그리고 관리국에선 실종된 시니어를 찾는데 당신이 도움이 될 것이라 판단했습니다.","JPN":"そして、管理局は行方不明のシニアを探すために、あなたの力が役に立つと判断しました。","ENG":"Also, the Administration has decided that you will be of help in searching for the missing Senior.","TWN":"而且管理局判斷妳會對尋找失蹤的Senior有幫助。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"오늘처럼 멋대로 사라지지만 않는다면 말이죠.","JPN":"今日みたいに勝手にいなくならない限り、です。","ENG":"Only if you don't randomly disappear like you did today, that is.","TWN":"只要別像今天一樣自顧自地消失不見就好。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네! 잭슨 씨를 찾을 수만 있다면, 저 완전 협조할게요!","JPN":"はい！　ジャクソンさんを見つけるためなら何でも協力します！","ENG":"Okay! If we can find Mr. Jackson, then I'm all in!","TWN":"好！只要能找到傑森，我會全力幫忙！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"……그렇게 말해서, 믿었는데.","JPN":"……って言われたから信じたのに。","ENG":"...That's what you said, and I believed you.","TWN":"……他這樣說，我就相信了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"날 속였어! 전 빠는 쪽이지, 빨리는 쪽이 아니라고요!","JPN":"騙された！　私は吸われるほうじゃなくて吸うほうなんだってば！","ENG":"You tricked me! I'm the one who sucks blood, not the other way around!","TWN":"結果他騙了我！我是吸血，而不是被吸血的一方！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아까운 내 피! 당장 돌려줘요!!","JPN":"私の血もったいない！　返して！！","ENG":"My precious blood! Give it back right now!!","TWN":"我珍貴的血！馬上還給我！！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"진정해. 이것도 잭슨 씨를 찾는데 필요한 절차라고.","JPN":"落ち着いて。これもジャクソンさんを探すためなの。","ENG":"Calm down. This is part of finding Mr. Jackson.","TWN":"冷靜點，這也是尋找傑森的必要流程。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"네 흡혈충동은 북방합의체의 수술로 생겨난 후천적 요소잖아?","JPN":"あなたの吸血衝動は、北方合意体の手術が原因で後天的に発生したものでしょ？","ENG":"Your vampiric impulse is an acquired factor from the Northern Union's surgery, right?","TWN":"妳的吸血衝動不就是因為北方和議會手術產生的後天因素嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그런데 흡혈한 사람이 어디 있는지 감으로 알 수 있다면…….","JPN":"血を吸った人がどこにいるのか、勘でわかるなら……","ENG":"If you can sense where someone you fed on is...","TWN":"但要是能憑感覺知道吸血的人在哪裡的話……"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 원리를 파악하면, 피를 이용해 잭슨 씨의 위치를 대략적으로 알 수 있다는 거니까.","JPN":"その原理を突き止めたら、あなたの血を利用してジャクソンさんの場所を推定できるってことだから。","ENG":"Then if we grasp the mechanism, we can use blood to roughly pinpoint Mr. Jackson's location.","TWN":"只要掌握那個原理，就能利用血液大概知道傑森的位置。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님이 의욕을 내는 경우는 흔치 않으니 얌전히 협력하시죠.","JPN":"シニア様がやる気を見せるのは珍しいことなので、大人しく協力してください。","ENG":"The Senior rarely gets motivated. Cooperate quietly.","TWN":"Senior有幹勁的情況並不常見，就請妳乖乖配合吧。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야…! 나 그래도, 최근에는 꽤 열심히 했다고?!","JPN":"ちょっと……！　最近は結構頑張ってると思うけど！？","ENG":"Hey...! I have been working pretty hard lately, okay?","TWN":"喂…！至少我最近還滿努力的？！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으으… 그래서, 뭔가 알아내신 게 있나요?","JPN":"うう……それで、何かわかったんですか？","ENG":"Ngh... So, did you learn anything?","TWN":"呃呃…所以妳有打探出什麼嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"미안. 이쪽은 전문 분야가 아니라서.","JPN":"ごめん。こっちは専門じゃなくて。","ENG":"Sorry. Not exactly my specialty.","TWN":"抱歉，這不是我的專業領域。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"크아아아악…!","JPN":"くああああっ……！","ENG":"Graaah...!","TWN":"呃啊啊啊啊…！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"야, 관리국 깡패… 이거 놔!","JPN":"このっ、管理局のごろつき……！　放せ！","ENG":"Let go of me... you Administration gangster!","TWN":"喂，管理局流氓…放開我！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"죄송합니다. 시니어님은 햇빛결핍증이라 목덜미를 통한 헌혈 행위는 위험할 것 같군요.","JPN":"失礼。シニア様は日光欠乏症のため、首元での献血は危険かと。","ENG":"My apologies. The Senior has a sunlight deficiency, so drawing blood at the nape would be risky.","TWN":"抱歉，Senior患有陽光缺乏症，通過後頸捐血應該會有危險。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그럼 내 피는…! 귀중한 내 피가 무용지물이 됐는데, 내 피느으은…!!","JPN":"じゃあ私の血は……！　大事な私の血が無駄になったのに、私の血はぁ……！！","ENG":"Then my blood...! My precious blood is wasted. My blooood...!!","TWN":"那我的血…！我珍貴的血就變成無用之物了，我的血…！！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…얘, 얘 원래 이렇게 난폭해?","JPN":"……こ、こいつ、もともとこんなに凶暴なわけ？","ENG":"...I-is she always this violent?","TWN":"…她、她本來就這麼粗暴嗎？"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"지속적인 갈증 현상으로 이성이 마비된 것 같군요.","JPN":"乾きが続いたせいで理性が麻痺したようですね。","ENG":"Looks like her reason is numbed by a persistent thirst.","TWN":"似乎是持續的渴望現象導致理性麻痺了。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다시 헌혈실에 집어넣어.","JPN":"献血室に戻して。","ENG":"Put her back in the donation room.","TWN":"再把她送進捐血室。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"난폭해지지 않게 혈액팩 하나 쥐여주고.","JPN":"暴れないように、血液パック1つ渡しといて。","ENG":"Give her a blood pack so she does not get rough.","TWN":"給她一袋血，別讓她變得粗暴。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Understood.","TWN":"我知道了。"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이, 이거 놔!","JPN":"は、放してよ！","ENG":"L-let go of me!","TWN":"放、放開我！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 피도 눈물도 없는 로터스 양아치들아…!!","JPN":"この、血の涙もないロータスのやつらめ……！！","ENG":"You heartless Lotus thugs...!","TWN":"你們這些沒血沒淚的洛德斯無賴…！！"},"stage":{"bg":"FACILITY","bgm":"THEMA_CITY_LOTUS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"흐으. 어째 실험실에 있을 때랑 엇비슷할 정도로 어지러운데.","JPN":"ふう……なんか、実験室にいた時と同じぐらい目眩がする。","ENG":"Hngh. I feel almost as woozy as I did back in the lab.","TWN":"呼呃，暈眩的程度怎麼會和在實驗室的時候差不多？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"역시, 틈을 봐서 도망쳐야 하나…….","JPN":"やっぱり、隙をついて逃げるしか……","ENG":"Maybe I should slip out when I get a chance...","TWN":"果然，應該要找機會逃跑嗎……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시로코바 씨? 잠깐 괜찮으신가요?","JPN":"シロコバさん？　少しいいですか？","ENG":"Ms. Shirokova? Do you have a moment?","TWN":"西羅克巴小姐？可以抽個空嗎？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"캬아아아악…!!","JPN":"きゃああああっ……！！","ENG":"Kyaaah...!!","TWN":"呃啊啊啊啊…！！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"피, 피를 뽑으려는 게 아니니 진정하세요.","JPN":"さ、採血じゃないので落ち着いてください。","ENG":"We are not here to draw blood. Please calm down.","TWN":"我、我不是要抽妳的血，請妳冷靜點。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"실은 친구분이 시로코바 씨를 찾아오셔서요.","JPN":"実は、シロコバさんのご友人が来ていまして。","ENG":"A friend has come to see you.","TWN":"其實是有朋友來找妳。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"친구요?","JPN":"友人？","ENG":"A friend?","TWN":"朋友？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이상하네요. 저를 만나러 올 사람은 기껏해야 관리자님 정도인데?","JPN":"おかしいですね。私に会いに来る人って、管理者さんぐらいしかいないけど。","ENG":"That's odd. The only one who ever visits me is the Administrator.","TWN":"真奇怪，會來見我的人頂多就是管理者啊？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만 그분이라면 방구석 시니어나 깡패를 거쳤을 테고, 음…….","JPN":"でもあの人なら、引きこもりシニアかごろつきを通したはずだし、うーん……","ENG":"And if it were him, he would have gotten past the hermit Senior and the gangster. Hmm...","TWN":"但他應該已經遇過房裡的Senior或流氓了，嗯……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"저기… 친구분께서 이걸 건네면 알 거라고 하셨는데, 어떠신가요?","JPN":"あの……ご友人が、これを見せればわかるとおっしゃってましたが。","ENG":"Um... your friend said you would know if I handed you this?","TWN":"那個…妳朋友說拿出這個妳就會知道，怎麼樣？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"What is this?","TWN":"這是？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L2_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 오늘 길에 별일 없었지?","JPN":"モ、モコ。今日は来る途中に特に何もなかったよね？","ENG":"F-Fluffox. Nothing bad on the way over, right?","TWN":"福、福實，今天在路上沒發生什麼事吧？"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L4_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L5_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"에헤헤. 장하다, 장해.","JPN":"えへへ、えらいね～","ENG":"Hehe. Good job, good job.","TWN":"嘿嘿嘿，好棒，真了不起。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"저기-. 당신, 북방합의체죠? 예전에 만난 기억이 있어요.","JPN":"あの～あなた、北方合意体の人ですよね？　確か前に会ったことがあるような。","ENG":"Hey. You are with the Northern Union, right? I remember you.","TWN":"那個，妳是北方和議會的人吧？我記得以前見過面。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어떻게 여기까지 왔는지는 고사하고, 합의체 소속이 제게 무슨 용건이에요?","JPN":"どうやってここに来たのか、は置いといて……合意体所属の人が私に何の用ですか？","ENG":"Never mind how you got in here. What business does a Northern Union person have with me?","TWN":"先不論妳是怎麼來到這裡的，和議會的人找我有什麼事？"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"유, 율리아 님이 예니카를 찾아가랬어요.","JPN":"ユ、ユリア様がイェニカを訪ねろって。","ENG":"M-Ms. Yulia told me to find you.","TWN":"茱、茱莉亞叫我去找耶妮卡。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예니카는 이번 임무에 꼭 필요한 존재니까, 만나서 도움을 받으래요.","JPN":"イェニカは今回の任務に絶対必要だから、会いに行って協力してもらうように言われました。","ENG":"She said you are essential to this mission and that I should ask for your help.","TWN":"她說耶妮卡是這次任務不可或缺的存在，要我見面之後尋求幫助。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…하, 그 음침녀. 몇 번 도와줬다고 내가 지 부하처럼 목줄이라도 찰 줄 아나?","JPN":"……は、あの陰湿女。何回か手助けしただけで、私が自分の部下になったとでも思ってるの？","ENG":"...*Sigh* That creepy woman. She thinks a couple favors means I'll wear her leash like a flunky.","TWN":"…哈，那個陰險的女人，只不過幫了幾次忙，就以為自己能把我當部下一樣使喚嗎？"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"유감이지만 거절할게요. 펠릭스에게 협력한 건 어디까지나 잭슨 씨 때문이거든요.","JPN":"残念ですが断ります。フェリックスに協力したのは、あくまでジャクソンさんのためだったんで。","ENG":"Sorry, I refuse. I only worked with Felix because of Mr. Jackson.","TWN":"雖然遺憾，但我要拒絕，我之所以會幫忙緋莉克絲說到底是因為傑森。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"애당초 합의체와 부딪힌 게 엊그제인데, 무슨 염치로 나한테 손을 건네는 거람?","JPN":"そもそも合意体とぶつかった直後だというのに、どの面下げて私に協力を求めるの？","ENG":"We were butting heads with the Northern Union just the other day. What nerve to hold out a hand to me now.","TWN":"當初跟和議會起衝突的事還像是昨天一樣，妳有什麼臉來向我伸手？"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"어… 안되는데.","JPN":"え……どうしよう。","ENG":"Uh... That won't do.","TWN":"呃…這樣不行。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"유, 율리아 님이 맡기신 일이라, 꼭 성공해야 하는데.","JPN":"ユ、ユリア様の命令だから、成功しないといけないのに。","ENG":"I-it is an assignment from Ms. Yulia. I have to succeed.","TWN":"這、這是茱莉亞交付的工作，我一定要成功。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L19_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아… 맞다! 아직 그걸 건네지 않았구나?","JPN":"あ……そうだ！　まだあれを渡してなかったね。","ENG":"Ah... right! I haven't given you this yet.","TWN":"啊…對了！我還沒拿出那個啊？"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"무슨 말을 하든 똑같아요. 협의체에 협력할 생각 따위-.","JPN":"何を言っても私の答えは変わらない。合意体に協力するつもりなんか……","ENG":"Whatever you say, my answer is the same. I won't help the Northern Union–","TWN":"不管妳說什麼都一樣，我不打算幫助和議會…"},"stage":{"bg":"LAB_02","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_TECH_03"},{"id":"L25_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아…!","JPN":"モ、モコ……！","ENG":"F-Fluffox...!","TWN":"福、福實…！"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"너… 뭐야?","JPN":"あなた……何者なの？","ENG":"What the...?","TWN":"妳…怎麼回事？"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어떻게 네가, 잭슨 씨의 시니어 코드를 가지고 있는 건데!","JPN":"なんであなたが、ジャクソンさんのシニアコードを持ってるの？","ENG":"How do you have Mr. Jackson's Senior Code?!","TWN":"妳怎麼會有傑森的Senior代碼！"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"설마 합의체 놈들이 잭슨 씨를…!!","JPN":"まさか合意体のやつらがジャクソンさんを……！","ENG":"Don't tell me the Northern Union did something to him...!!","TWN":"難道和議會那些傢伙把傑森…！！"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아, 아니에요. 그건 잭슨 씨가 율리아 님에게 건넨 거라고요.","JPN":"ち、違います。それはジャクソンさんがユリア様に預けたんです。","ENG":"N-no. Mr. Jackson gave that to Ms. Yulia.","TWN":"不、不是，那是傑森自己給茱莉亞的。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그러니까 폭실이는 놔주세요…!!","JPN":"だからモコを放してください……！！","ENG":"So please, let Fluffox go...!!","TWN":"所以請妳放開福實…！！"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아아아…!!","JPN":"モ、モコぉぉぉ……！！","ENG":"F-Fluffooox...!","TWN":"福、福實啊啊啊…！！"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L38_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그쪽을 믿는 게 아니에요. 제 의문이 풀릴 때까지, 합의체에 협력할 생각도 없고요.","JPN":"そっちのことは信用してません。疑問が解けるまで、合意体に協力するつもりもありません。","ENG":"I still don't trust you. And I still have no intention of helping the Northern Union until my doubts are cleared.","TWN":"我並不是相信妳，直到我的疑問解開之前，都不打算跟和議會合作。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨가 펠릭스에게 시니어 코드를 넘긴 이유가 뭐죠?","JPN":"ジャクソンさんがフェリックスにシニアコードを渡した理由は何ですか？","ENG":"Why would Mr. Jackson hand his Senior Code to Felix?","TWN":"傑森為什麼會把Senior代碼交給緋莉克絲？"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"애당초, 사라진 잭슨 씨가 어째서 북방합의체의 영토로 향했던 건가요?","JPN":"そもそも、消えたジャクソンさんはなぜ北方合意体の領土に向かったんですか？","ENG":"And why was he headed into Northern Union territory in the first place before he disappeared?","TWN":"消失的傑森當初怎麼會前往北方和議會的領土？"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그건 저도 모르겠어요.","JPN":"そ、それは私にもわかりません。","ENG":"I-I don't know that either.","TWN":"這、這我也不知道。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"でも……","ENG":"But...","TWN":"不過……"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"유, 율리아 님은 예니카가 찾는 답이 이 안에 있다고 말하셨어요.","JPN":"ユ、ユリア様は、イェニカが求めている答えがこの中にあるとおっしゃってました。","ENG":"M-Ms. Yulia said the answers you want are inside this.","TWN":"茱、茱莉亞說妳尋找的答案在這裡面。"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"알겠습니다, 예니카.","JPN":"わかりました、イェニカ。","ENG":"Understood, Yanikka.","TWN":"知道了，耶妮卡。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACKSON_NPC_NULL_NULL","text":{"KOREA":"이후의 일은, 당신이 어떤 <color=#ffd34c>선택</color>을 내리든 존중하죠.","JPN":"今後のことについてあなたがどんな<color=#ffd34c>選択</color>をしても、わたくしはそれを尊重します。","ENG":"Whatever <color=#ffd34c>choice</color> you make after this, I'll respect it.","TWN":"之後的事，不管妳做出什麼<color=#ffd34c>選擇</color>，我都會尊重。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JACKSON_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그때는 왜 그런 말을 하나 싶었는데.","JPN":"あの時は、あの言葉の意味がわからなかったけど。","ENG":"Back then, I wondered why he said that.","TWN":"我那時候還想他為什麼會這麼說。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"잭슨 씨… 처음부터 이렇게 될 줄 알고 있었을지도 모르겠네.","JPN":"ジャクソンさん……最初からこうなるってわかってたのかもね。","ENG":"Maybe Mr. Jackson knew from the start it would come to this.","TWN":"傑森…也許從一開始就知道會變成這樣。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"저, 저기…….","JPN":"あ、あの……","ENG":"U-um...","TWN":"那、那個……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"걱정 마세요. 북방합의체랑 다르게 전 공과 사가 확실한 사람이니까요.","JPN":"心配要りません。北方合意体と違って、私は公私混同しない人なんで。","ENG":"Don't worry. Unlike the Northern Union, I keep business and personal separate.","TWN":"別擔心，我和北方和議會不一樣，是個公私分明的人。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>2급 관리자 잭슨 확인.</color>","JPN":"<color=#ffd34c>2級管理者ジャクソンを確認。</color>","ENG":"<color=#ffd34c>Senior Administrator Jackson confirmed.</color>","TWN":"<color=#ffd34c>確認為2級管理者傑森。</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>등록된 단말로부터 정보 열람을 승인합니다.</color>","JPN":"<color=#ffd34c>登録された端末からの情報閲覧を承認します。</color>","ENG":"<color=#ffd34c>Access from the registered terminal approved.</color>","TWN":"<color=#ffd34c>允許從已登錄的終端查看情報。</color>"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"만약 잭슨 씨가 말했던 챔버의 위기가 다가온다면…….","JPN":"もし、ジャクソンさんが言ってたチェンバーの危機が本当に迫ってきたら……","ENG":"If the crisis Mr. Jackson spoke of is coming to Chamber...","TWN":"如果傑森說過的密室危機到來的話……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"기분 더럽지만, 그 여자가 짠 판 위에서 놀아나 줄게요.","JPN":"気乗りしないけど、あの女の駒になってあげますよ。","ENG":"Then fine. As lousy as it feels, I'll dance on the stage that woman set.","TWN":"雖然心情糟糕透頂，但我會在那女人設的局陪她玩一場。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);e